import json
import os
from datetime import datetime

EVENT_LOG_PATH = "data/module_events.log"
os.makedirs("data", exist_ok=True)


class EventBus:
    def __init__(self, path: str = EVENT_LOG_PATH):
        self.path = path

    def publish(self, module: str, event: str, tags=None):
        entry = {
            "ts": datetime.utcnow().isoformat(),
            "module": module,
            "event": event,
            "tags": tags or [],
        }
        try:
            with open(self.path, "a") as f:
                f.write(json.dumps(entry) + "\n")
        except Exception:
            # Never break the system on logging
            pass

    def read(self, limit: int = 200):
        if not os.path.exists(self.path):
            return []
        events = []
        try:
            with open(self.path, "r") as f:
                for line in f.readlines()[-limit:]:
                    try:
                        events.append(json.loads(line))
                    except:
                        continue
        except Exception:
            return []
        return events

class ModuleRegistry:
    def __init__(self):
        self.modules = {}

    def register(self, name: str, module_obj):
        self.modules[name] = module_obj

    def get(self, name: str):
        return self.modules.get(name)

    def list(self):
        return list(self.modules.keys())

    def capabilities(self):
        caps = {}
        for name, mod in self.modules.items():
            cap_fn = getattr(mod, "capabilities", lambda: [])
            ver_fn = getattr(mod, "version", lambda: "0.0.0")
            caps[name] = {
                "version": ver_fn(),
                "capabilities": cap_fn(),
            }
        return caps

import json
import os
from typing import Dict, Any, List

POLICY_PATH = "config/policy.aegis.json"


class PolicyEngine:
    def __init__(self, path: str = POLICY_PATH):
        self.path = path
        self.rules: list[dict] = []
        self.load()

    def load(self):
        if not os.path.exists(self.path):
            self.rules = []
            return
        try:
            with open(self.path, "r") as f:
                data = json.load(f)
                self.rules = data.get("rules", [])
        except Exception:
            self.rules = []

    def evaluate(self, posture_block: Dict[str, Any]) -> List[Dict[str, Any]]:
        posture = posture_block.get("posture")
        tags = posture_block.get("tags", [])
        results: List[Dict[str, Any]] = []

        for rule in self.rules:
            cond = rule.get("when", {})
            match = True

            if "posture" in cond and cond["posture"] != posture:
                match = False

            if "tags_any" in cond:
                if not any(t in tags for t in cond["tags_any"]):
                    match = False

            if not match:
                continue

            for action in rule.get("actions", []):
                results.append(action)

        return results

