def _derive_summary(path: Path, text: str, title: str) -> str:
    if path.suffix.lower() == ".py":
        try:
            tree = ast.parse(text)
            doc = ast.get_docstring(tree)
            if doc:
                return " ".join(doc.split())[:280]
        except SyntaxError:
            pass
    if path.suffix.lower() == ".md":
        # First paragraph after the title.
        paras = re.split(r"\n\s*\n", text.strip())
        for p in paras:
            p = p.strip()
            if p.startswith("#") or not p:
                continue
            return " ".join(p.split())[:280]
    return title[:280]


def _chunk(text: str) -> List[str]:
    if len(text.encode("utf-8")) <= CHUNK_THRESHOLD:
        return [text]
    chunks: List[str] = []
    buf: List[str] = []
    size = 0
    for line in text.splitlines(keepends=True):
        line_size = len(line.encode("utf-8"))
        if size + line_size > CHUNK_TARGET and buf:
            chunks.append("".join(buf))
            buf = [line]
            size = line_size
        else:
            buf.append(line)
            size += line_size
    if buf:
        chunks.append("".join(buf))
    return chunks


